#include <winsock2.h>
#include <ws2tcpip.h>
#include <iostream>
#include <string>
#include <memory>

#pragma comment(lib, "ws2_32.lib")

int main()
{
    WSADATA wsaData;
    int iResult = WSAStartup(MAKEWORD(2, 2), &wsaData);
    if (iResult != 0)
    {
        std::cerr << "WSAStartup failed: " << iResult << std::endl;
        return 1;
    }

    addrinfo hints = {};
    hints.ai_family = AF_UNSPEC;
    hints.ai_socktype = SOCK_STREAM;
    hints.ai_protocol = IPPROTO_TCP;

    addrinfo* result = nullptr;
    iResult = getaddrinfo("httpbin.org", "80", &hints, &result);
    if (iResult != 0)
    {
        std::cerr << "getaddrinfo failed: " << iResult << std::endl;
        WSACleanup();
        return 1;
    }

    SOCKET sock = socket(result->ai_family, result->ai_socktype, result->ai_protocol);
    if (sock == INVALID_SOCKET)
    {
        std::cerr << "socket failed: " << WSAGetLastError() << std::endl;
        freeaddrinfo(result);
        WSACleanup();
        return 1;
    }

    iResult = connect(sock, result->ai_addr, (int)result->ai_addrlen);
    if (iResult == SOCKET_ERROR)
    {
        std::cerr << "connect failed: " << WSAGetLastError() << std::endl;
        closesocket(sock);
        freeaddrinfo(result);
        WSACleanup();
        return 1;
    }

    std::string request = "GET / HTTP/1.1\r\nHost: httpbin.org\r\nConnection: close\r\n\r\n";
    iResult = send(sock, request.c_str(), (int)request.length(), 0);
    if (iResult == SOCKET_ERROR)
    {
        std::cerr << "send failed: " << WSAGetLastError() << std::endl;
        closesocket(sock);
        freeaddrinfo(result);
        WSACleanup();
        return 1;
    }

    std::cout << "Sent request successfully" << std::endl;

    closesocket(sock);
    freeaddrinfo(result);
    WSACleanup();
    return 0;
}
